import os
import logging
from azure.functions import FunctionContext, HttpRequest, Input, Output
from azure.storage.blob import BlobServiceClient, ContainersClient, BlobClient
from azure.cosmosdb.sql import CosmosClient, Database, Container
from azure.eventgrid.events import EventGridEvent
from azure.eventgrid.subscription_client import SubscriptionClient
from azure.keyvault.secrets import SecretClient

logging.getLogger("azure").setLevel(logging.INFO)

def main(req: HttpRequest) -> str:
    func_context = FunctionContext()
    if req.method == "POST":
        storage_account_name = os.environ["STORAGE_ACCOUNT"]
        blob_service_client = BlobServiceClient(os.environ["AzureWebJobsStorage"], credential=func_context.credential)
        container_name = req.params.get('container')
        cosmos_account = os.environ["AZURE_COSMOSDB_ACCOUNT"]
        cosmos_key = os.environ["AZURE_COSMOSDB_KEY"]
        event_grid_topic = os.environ["AZURE_EVENTGRID_TOPIC"]

        # Process Blob Storage and write to Cosmos DB
        process_and_write(blob_service_client, container_name)

        # Send Event Grid Notification
        send_event_grid(event_grid_topic)

        return "File processed and sent notifications."

    return "This HTTP triggered function executes a blob processing workflow in Azure Functions."

def process_and_write(blob_service_client, container_name):
    # Initialize Cosmos DB
    cosmos_client = CosmosClient(f"{cosmos_account}.documents.azure.com", cosmos_key)
    db = cosmos_client.get_database_client("dbname")
    container = db.create_container_if_not_exists("containername")

    # Get the blob client for the specified container
    containers_client = blob_service_client.get_container_client(container_name)
    blobs_list = containers_client.list_blobs()

    for blob in blobs_list:
        # Retrieve blob content and write to Cosmos DB
        blob_client = blob_service_client.get_blob_client(container_name, blob.name)
        data = blob_client.download_blob().content_as_text()
        container.create_item({"id": blob.name, "data": data}, partition_key=str(blob.name))

def send_event_grid(topic):
    # Initialize Event Grid Subscription Client
    subscription_client = SubscriptionClient(endpoint=os.environ["AZURE_EVENTGRID_TOPIC"], credential=func_context.credential)

    # Define the event schema
    event_schema = {
        "type": "object",
        "properties": {
            "file": {"type": "string"}
        },
        "required": ["file"]
    }

    # Create and send an event to Event Grid Topic
    event = EventGridEvent(topic=topic, data_version='2.0', data={"file": "Processed File Name"})
    subscription_client.send_event(event)